sp_widget.client_script:
api.controller = function ($scope) {
    const c = this;

    c.expandedNodes = {};

    c.getRootNodes = () => c.data.nodes.filter((node) => !node.parent);

    c.getChildren = (parentId) =>
        c.data.nodes.filter((node) => node.parent === parentId);

    c.hasChildren = (nodeId) =>
        c.data.nodes.some((node) => node.parent === nodeId);

    c.isExpanded = (nodeId) => c.expandedNodes[nodeId] === true;

    c.toggleExpanded = (nodeId) => {
        c.expandedNodes[nodeId] = !c.expandedNodes[nodeId];
    };

    c.getNodeTemplate = function (node) {
        return node.template;
    };

    c.executeCallback = function (callbackName, nodeData) {
        if (
            c.data.availableCallbacks &&
            c.data.availableCallbacks[callbackName]
        ) {
            const functionPath = c.data.availableCallbacks[callbackName];

            if (functionPath.startsWith("parent.")) {
                const functionName = functionPath.replace("parent.", "");
                if ($scope.$parent && $scope.$parent.c[functionName]) {
                    $scope.$parent.c[functionName](nodeData);
                }
            }
        } else {
            console.warn("Callback not found:", callbackName);
        }
    };

    c.data.nodes.forEach((node) => {
        if (c.hasChildren(node.id)) c.expandedNodes[node.id] = true;
    });
};

sp_widget.css:
$tree-indent-horizontal: 320px;
$tree-indent-vertical: 8px;

$tree-border-width: 2px;
$tree-border-color: #e0e0e0;
$tree-vertical-line-offset: 20px;
$tree-horizontal-line-length: (
    $tree-indent-horizontal - $tree-vertical-line-offset
);

$tree-horizontal-line-position: 20px;
$tree-mask-start-position: (
    $tree-horizontal-line-position + $tree-border-width
);
$tree-mask-extend-bottom: ($tree-indent-vertical * 3);
$tree-background-color: white;

$tree-container-padding: 16px;
$tree-content-gap: 8px;
$tree-card-min-width: 300px;
$tree-card-max-width: 500px;

$tree-button-alignment-offset: $tree-indent-vertical;

.tree-container {
    padding: $tree-container-padding;
}

.tree-node {
    position: relative;
    margin-bottom: $tree-indent-vertical;

    &:has(.tree-children)::after {
        content: "";
        position: absolute;
        left: $tree-vertical-line-offset;
        top: 100%;
        width: $tree-border-width;
        height: $tree-indent-vertical;
        background: $tree-border-color;
        z-index: 1;
    }
}

.tree-children {
    margin-left: $tree-indent-horizontal;
    position: relative;
    margin-top: $tree-indent-vertical;

    &::before {
        content: "";
        position: absolute;
        left: (-$tree-indent-horizontal + $tree-vertical-line-offset);
        top: 0;
        bottom: 0;
        width: $tree-border-width;
        background: $tree-border-color;
    }

    > div:last-child > .tree-node::before {
        content: "";
        position: absolute;
        left: (-$tree-indent-horizontal + $tree-vertical-line-offset);
        top: $tree-mask-start-position;
        bottom: (-$tree-mask-extend-bottom);
        width: $tree-border-width;
        background: $tree-background-color;
    }

    > div > .tree-node::after {
        content: "";
        position: absolute;
        left: (-$tree-indent-horizontal + $tree-vertical-line-offset);
        top: $tree-horizontal-line-position;
        width: $tree-horizontal-line-length;
        height: $tree-border-width;
        background: $tree-border-color;
    }
}

.tree-node .tree-node .card {
    opacity: 0.95;
    transform: scale(0.98);
}

.tree-node .tree-node .tree-node .card {
    opacity: 0.9;
    transform: scale(0.96);
}

.tree-node .card {
    margin-left: 0;
    margin-bottom: 0 !important;
    width: $tree-card-min-width;
    min-width: $tree-card-min-width;
    max-width: $tree-card-max-width;
}

.tree-node-content {
    display: flex;
    align-items: flex-start;
    gap: $tree-content-gap;
}

.tree-card-wrapper {
    flex-shrink: 1;
    min-width: 0;
}

.tree-toggle-button {
    flex-shrink: 0;
    align-self: flex-start;
    margin-top: $tree-button-alignment-offset;
}

sp_widget.script:
(function () {
    const transactionId = input?.transactionId || gs.generateGUID();
    data.transactionId = transactionId;

    const logger = new Logger({
        transactionId: transactionId,
        source: "scm-tree.server.js",
        includeTimeStamp: true,
        includeUserInfo: true,
        includeSessionId: true,
    });

    data.nodes = options.nodes;

    data.availableCallbacks = options.availableCallbacks || {};

    logger.debug({
        input: input,
        data: data,
        options: options,
    });
})();
